/**
 * Task Router
 *
 * Uses phi4-mini-reasoning to classify tasks and route them
 * to the appropriate model or agent.
 */

import { createOllamaClient, OllamaClient, REQUIRED_MODELS } from './ollama';

export type TaskCategory =
  | 'code' // Code generation, review, debugging
  | 'reasoning' // Analysis, planning, complex decisions
  | 'simple' // Simple questions, clarifications
  | 'cloud'; // Complex features requiring Claude Opus

export interface RoutingResult {
  category: TaskCategory;
  model: string;
  confidence: number;
  reasoning: string;
}

export interface RouterOptions {
  client?: OllamaClient;
  routerModel?: string;
}

const ROUTER_SYSTEM_PROMPT = `You are a task router for a software development AI harness.
Your job is to classify tasks and route them to the appropriate model.

Available categories:
- CODE: Code generation, code review, debugging, refactoring, tests
- REASONING: Analysis, planning, architecture decisions, problem-solving
- SIMPLE: Quick questions, clarifications, status updates
- CLOUD: Complex features, UI/UX design, creative work (requires Claude Opus)

Respond ONLY with a JSON object in this exact format:
{
  "category": "CODE|REASONING|SIMPLE|CLOUD",
  "confidence": 0.0-1.0,
  "reasoning": "Brief explanation"
}

Be concise. No additional text.`;

export class TaskRouter {
  private client: OllamaClient;
  private routerModel: string;

  constructor(options: RouterOptions = {}) {
    this.client = options.client || createOllamaClient();
    this.routerModel = options.routerModel || REQUIRED_MODELS.router.name;
  }

  /**
   * Check if router is available
   */
  async isAvailable(): Promise<boolean> {
    const isRunning = await this.client.isRunning();
    if (!isRunning) return false;

    return this.client.hasModel(this.routerModel);
  }

  /**
   * Route a task to the appropriate model
   */
  async route(task: string): Promise<RoutingResult> {
    const response = await this.client.generate({
      model: this.routerModel,
      system: ROUTER_SYSTEM_PROMPT,
      prompt: `Task: ${task}`,
      temperature: 0.1,
      numPredict: 200,
    });

    if (!response) {
      return this.defaultRouting(task);
    }

    try {
      const parsed = JSON.parse(response.response.trim()) as {
        category: string;
        confidence: number;
        reasoning: string;
      };

      const category = this.normalizeCategory(parsed.category);
      const model = this.getModelForCategory(category);

      return {
        category,
        model,
        confidence: Math.min(1, Math.max(0, parsed.confidence || 0.5)),
        reasoning: parsed.reasoning || 'No reasoning provided',
      };
    } catch {
      return this.defaultRouting(task);
    }
  }

  /**
   * Batch route multiple tasks
   */
  async routeBatch(tasks: string[]): Promise<RoutingResult[]> {
    const results: RoutingResult[] = [];

    for (const task of tasks) {
      results.push(await this.route(task));
    }

    return results;
  }

  private normalizeCategory(category: string): TaskCategory {
    const normalized = category.toUpperCase().trim();

    switch (normalized) {
      case 'CODE':
        return 'code';
      case 'REASONING':
        return 'reasoning';
      case 'SIMPLE':
        return 'simple';
      case 'CLOUD':
        return 'cloud';
      default:
        return 'reasoning';
    }
  }

  private getModelForCategory(category: TaskCategory): string {
    switch (category) {
      case 'code':
        return REQUIRED_MODELS.code.name;
      case 'reasoning':
        return REQUIRED_MODELS.reasoning.name;
      case 'simple':
        return REQUIRED_MODELS.router.name;
      case 'cloud':
        return 'claude-opus-4-5-20251101';
      default:
        return REQUIRED_MODELS.reasoning.name;
    }
  }

  private defaultRouting(task: string): RoutingResult {
    // Simple heuristics for fallback
    const taskLower = task.toLowerCase();

    if (
      taskLower.includes('code') ||
      taskLower.includes('function') ||
      taskLower.includes('implement') ||
      taskLower.includes('fix bug') ||
      taskLower.includes('test') ||
      taskLower.includes('refactor')
    ) {
      return {
        category: 'code',
        model: REQUIRED_MODELS.code.name,
        confidence: 0.6,
        reasoning: 'Fallback: detected code-related keywords',
      };
    }

    if (
      taskLower.includes('design') ||
      taskLower.includes('ui') ||
      taskLower.includes('ux') ||
      taskLower.includes('feature') ||
      taskLower.includes('creative')
    ) {
      return {
        category: 'cloud',
        model: 'claude-opus-4-5-20251101',
        confidence: 0.6,
        reasoning: 'Fallback: detected complex/creative task keywords',
      };
    }

    if (
      taskLower.includes('plan') ||
      taskLower.includes('analyze') ||
      taskLower.includes('decide') ||
      taskLower.includes('architecture')
    ) {
      return {
        category: 'reasoning',
        model: REQUIRED_MODELS.reasoning.name,
        confidence: 0.6,
        reasoning: 'Fallback: detected reasoning-related keywords',
      };
    }

    return {
      category: 'reasoning',
      model: REQUIRED_MODELS.reasoning.name,
      confidence: 0.3,
      reasoning:
        'Fallback: no specific keywords detected, defaulting to reasoning',
    };
  }
}

/**
 * Create a task router
 */
export function createRouter(options?: RouterOptions): TaskRouter {
  return new TaskRouter(options);
}

